-- This SQL script sets up the database schema for the Omni-Core ERP system\n-- utilizing ACID-compliant SQLite features\n\n-- Enable Write-Ahead Logging (WAL) mode\nPRAGMA journal_mode=WAL;\n\n-- Table for Products\nCREATE TABLE products (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    name TEXT NOT NULL,\n    description TEXT,\n    price REAL NOT NULL,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for Sales\nCREATE TABLE sales (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    product_id INTEGER NOT NULL,\n    quantity INTEGER NOT NULL,\n    total_price REAL NOT NULL,\n    sale_date DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (product_id) REFERENCES products(id)\n);\n\n-- Table for Items\nCREATE TABLE items (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    product_id INTEGER NOT NULL,\n    stock INTEGER NOT NULL,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (product_id) REFERENCES products(id)\n);\n\n-- Table for Payments\nCREATE TABLE payments (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    sale_id INTEGER NOT NULL,\n    amount REAL NOT NULL,\n    payment_date DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (sale_id) REFERENCES sales(id)\n);\n\n-- Table for Audit Logs\nCREATE TABLE audit_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    action TEXT NOT NULL,\n    table_name TEXT NOT NULL,\n    record_id INTEGER NOT NULL,\n    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for Reserved Stock\nCREATE TABLE reserved_stock (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    item_id INTEGER NOT NULL,\n    reserved_quantity INTEGER NOT NULL,\n    reserved_date DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (item_id) REFERENCES items(id)\n);\n